import java.util.ArrayList;

public static ArrayList<Integer> circularPermutation(int n, int start) {
    ArrayList<Integer> result = new ArrayList<>(1 << n);
    for (int i = 0; i < (1 << n); ++i) {
        result.add(start ^ (i ^ (i >> 1)));
    }
    return result;
}
```


